('business:3-6-training-and-development:fib:f227cb18', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 2, '{"question": "Induction training is designed to introduce a new worker to the _____, their colleagues, and the _____ of the business.", "blankOptions": {"B1": ["vocational", "workplace", "short-term", "skills"], "B2": ["retention", "development", "culture", "potential"]}}'::jsonb, '{"blanks": {"B1": "workplace", "B2": "culture"}}'::jsonb),
