('business:3-6-training-and-development:fib:3f531583', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 1, '{"question": "An apprenticeship is a long-term development programme that leads to a _____ qualification and combines on- and off-the-job learning.", "blankOptions": {"B1": ["vocational", "short-term", "culture", "cheaper"]}}'::jsonb, '{"blanks": {"B1": "vocational"}}'::jsonb),
