('business:3-6-training-and-development:fib:e4045564', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 1, '{"question": "A _____ shortage occurs when businesses cannot recruit workers with the skills they need.", "blankOptions": {"B1": ["on-the-job", "short-term", "skills", "academic"]}}'::jsonb, '{"blanks": {"B1": "skills"}}'::jsonb),
