('business:3-6-training-and-development:fib:c617e0aa', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 2, '{"question": "_____ qualifications are job-specific and gained through practical and classroom learning, whereas _____ qualifications are more general and theory-based.", "blankOptions": {"B1": ["vocational", "cheaper", "Vocational", "output"], "B2": ["academic", "qualification", "short-term", "off-the-job"]}}'::jsonb, '{"blanks": {"B1": "Vocational", "B2": "academic"}}'::jsonb),
