('business:3-6-training-and-development:fib:b6d6d81b', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 1, '{"question": "One benefit of off-the-job training is that it can be delivered in a _____ environment, which is essential for safety-critical roles such as cabin crew.", "blankOptions": {"B1": ["safe", "potential", "vocational", "expensive"]}}'::jsonb, '{"blanks": {"B1": "safe"}}'::jsonb),
('business:3-6-training-and-development:match:15f5f296', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Training”?", "options": ["Long-term learning aimed at growing a worker''s overall potential for future roles.", "Short-term, job-specific learning to improve a worker''s performance in their current role.", "Training delivered at the workplace while the employee is performing their normal duties.", "Training delivered away from the employee''s normal job, often at a college or training centre."]}'::jsonb, '{"answer": 1, "explain": "“Training” means: Short-term, job-specific learning to improve a worker''s performance in their current role."}'::jsonb),
('business:3-6-training-and-development:match:fedda862', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Development”?", "options": ["Long-term learning aimed at growing a worker''s overall potential for future roles.", "Training delivered at the workplace while the employee is performing their normal duties.", "Training delivered away from the employee''s normal job, often at a college or training centre.", "Training to introduce a new employee to the business, workplace, colleagues, and health and safety procedures."]}'::jsonb, '{"answer": 0, "explain": "“Development” means: Long-term learning aimed at growing a worker''s overall potential for future roles."}'::jsonb),
('business:3-6-training-and-development:match:6aaa9f86', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “On-the-job training”?", "options": ["Training delivered at the workplace while the employee is performing their normal duties.", "Training delivered away from the employee''s normal job, often at a college or training centre.", "Training to introduce a new employee to the business, workplace, colleagues, and health and safety procedures.", "A long-term development programme combining workplace experience and off-the-job study, leading to a vocational qualification."]}'::jsonb, '{"answer": 0, "explain": "“On-the-job training” means: Training delivered at the workplace while the employee is performing their normal duties."}'::jsonb),
('business:3-6-training-and-development:match:a2edc240', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Off-the-job training”?", "options": ["Training to introduce a new employee to the business, workplace, colleagues, and health and safety procedures.", "A long-term development programme combining workplace experience and off-the-job study, leading to a vocational qualification.", "Training delivered away from the employee''s normal job, often at a college or training centre.", "Long-term programmes (vocational or academic) designed to realise the full potential of a worker."]}'::jsonb, '{"answer": 2, "explain": "“Off-the-job training” means: Training delivered away from the employee''s normal job, often at a college or training centre."}'::jsonb),
('business:3-6-training-and-development:match:c7962cab', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Induction training”?", "options": ["A long-term development programme combining workplace experience and off-the-job study, leading to a vocational qualification.", "Long-term programmes (vocational or academic) designed to realise the full potential of a worker.", "Training to introduce a new employee to the business, workplace, colleagues, and health and safety procedures.", "A job-specific qualification gained through practical and classroom learning, e.g. an NVQ."]}'::jsonb, '{"answer": 2, "explain": "“Induction training” means: Training to introduce a new employee to the business, workplace, colleagues, and health and safety procedures."}'::jsonb),
('business:3-6-training-and-development:match:781a4a49', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Apprenticeship”?", "options": ["A long-term development programme combining workplace experience and off-the-job study, leading to a vocational qualification.", "Long-term programmes (vocational or academic) designed to realise the full potential of a worker.", "A job-specific qualification gained through practical and classroom learning, e.g. an NVQ.", "A general, theory-based qualification such as a GCSE, A Level, or degree."]}'::jsonb, '{"answer": 0, "explain": "“Apprenticeship” means: A long-term development programme combining workplace experience and off-the-job study, leading to a vocational qualification."}'::jsonb),
('business:3-6-training-and-development:match:87d2d619', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Professional development”?", "options": ["A job-specific qualification gained through practical and classroom learning, e.g. an NVQ.", "Long-term programmes (vocational or academic) designed to realise the full potential of a worker.", "A general, theory-based qualification such as a GCSE, A Level, or degree.", "Output per worker — a measure of how efficiently employees produce goods or services."]}'::jsonb, '{"answer": 1, "explain": "“Professional development” means: Long-term programmes (vocational or academic) designed to realise the full potential of a worker."}'::jsonb),
('business:3-6-training-and-development:match:ae269d02', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Vocational qualification”?", "options": ["A general, theory-based qualification such as a GCSE, A Level, or degree.", "Output per worker — a measure of how efficiently employees produce goods or services.", "A job-specific qualification gained through practical and classroom learning, e.g. an NVQ.", "A situation where businesses cannot recruit workers with the specific skills they require."]}'::jsonb, '{"answer": 2, "explain": "“Vocational qualification” means: A job-specific qualification gained through practical and classroom learning, e.g. an NVQ."}'::jsonb),
('business:3-6-training-and-development:match:de0be79a', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Academic qualification”?", "options": ["Output per worker — a measure of how efficiently employees produce goods or services.", "A general, theory-based qualification such as a GCSE, A Level, or degree.", "A situation where businesses cannot recruit workers with the specific skills they require.", "Successfully keeping workers employed at the business rather than them leaving to work elsewhere."]}'::jsonb, '{"answer": 1, "explain": "“Academic qualification” means: A general, theory-based qualification such as a GCSE, A Level, or degree."}'::jsonb),
('business:3-6-training-and-development:match:1db86f31', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Productivity”?", "options": ["A situation where businesses cannot recruit workers with the specific skills they require.", "Successfully keeping workers employed at the business rather than them leaving to work elsewhere.", "Short-term, job-specific learning to improve a worker''s performance in their current role.", "Output per worker — a measure of how efficiently employees produce goods or services."]}'::jsonb, '{"answer": 3, "explain": "“Productivity” means: Output per worker — a measure of how efficiently employees produce goods or services."}'::jsonb),
('business:3-6-training-and-development:match:a1e2ce90', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Skills shortage”?", "options": ["A situation where businesses cannot recruit workers with the specific skills they require.", "Successfully keeping workers employed at the business rather than them leaving to work elsewhere.", "Short-term, job-specific learning to improve a worker''s performance in their current role.", "Long-term learning aimed at growing a worker''s overall potential for future roles."]}'::jsonb, '{"answer": 0, "explain": "“Skills shortage” means: A situation where businesses cannot recruit workers with the specific skills they require."}'::jsonb),
('business:3-6-training-and-development:match:e40ce5e4', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retention”?", "options": ["Short-term, job-specific learning to improve a worker''s performance in their current role.", "Successfully keeping workers employed at the business rather than them leaving to work elsewhere.", "Long-term learning aimed at growing a worker''s overall potential for future roles.", "Training delivered at the workplace while the employee is performing their normal duties."]}'::jsonb, '{"answer": 1, "explain": "“Retention” means: Successfully keeping workers employed at the business rather than them leaving to work elsewhere."}'::jsonb),
('business:3-7-employment-law:exam:c5b2a9f9', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'exam', 'mcq', 1, '{"num": "Q2", "question": "A contract of employment is:", "options": ["A diagram showing the formal lines of authority in a business", "A formal document outlining the objectives of a business", "A law that makes discrimination in the workplace illegal", "A legal agreement between an employer and an employee"], "hint": "Think about what a contract fundamentally is — a legal relationship between two parties.", "starter": "A contract of employment is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 1 mark (AO1a)</h5><p><strong>D: A legal agreement between an employer and an employee.</strong></p><ul><li><strong>Why A is wrong:</strong> A diagram showing lines of authority is an organisational chart — it has nothing to do with employment contracts.</li><li><strong>Why B is wrong:</strong> A document outlining business objectives describes a business plan or mission statement.</li><li><strong>Why C is wrong:</strong> The law making workplace discrimination illegal is the Equality Act 2010 — not a contract of employment.</li><li><strong>Why D is correct:</strong> A contract of employment is the legal agreement formed between employer and employee when a job offer is accepted. It does not have to be in writing.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-7-employment-law:exam:40319e36', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'exam', 'mcq', 1, '{"num": "Q5", "question": "The average amount of time that Emma has worked during the 17-week period is:", "options": ["0.96 hours per week", "16.29 hours per week", "46 hours per week", "13,294 hours per week"], "caseStudy": "Employment legislation states that an employee cannot be forced to work more than an average of 48 hours per week in a 17-week period. Emma worked 782 hours in a 17-week period.", "hint": "Use the formula: Total hours ÷ 17 = average weekly hours.", "starter": "Average hours per week = total hours ÷ 17 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 1 mark (AO2)</h5><p><strong>C: 46 hours per week.</strong></p><p>782 &divide; 17 = <strong>46 hours per week</strong>. This is below the 48-hour limit, so no law has been broken.</p><ul><li><strong>Why A is wrong:</strong> 0.96 comes from dividing 17 by 782 — the formula is reversed.</li><li><strong>Why B is wrong:</strong> 16.29 comes from dividing 782 by 48 — using the wrong divisor.</li><li><strong>Why D is wrong:</strong> 13,294 comes from multiplying 782 by 17 — multiplying instead of dividing.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-7-employment-law:exam:c56ac65c', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which one of the following is required by law?", "options": ["All employees must be given a voucher for a free eyesight test each year", "Employees who work from home must work a maximum of 16 hours a week", "Everyone who is self-employed must have private medical insurance", "Full-time employees must be given at least 5.6 weeks paid holiday per year"], "hint": "Think about which of these is an actual legal entitlement for all workers under UK employment law.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 1 mark (AO1a)</h5><p><strong>D: Full-time employees must be given at least 5.6 weeks paid holiday per year.</strong></p><ul><li><strong>Why A is wrong:</strong> Free eyesight tests are only required for employees who regularly use display screen equipment (DSE) — not all employees.</li><li><strong>Why B is wrong:</strong> There is no 16-hour maximum for homeworkers. The Working Time Directive''s 48-hour average applies regardless of location.</li><li><strong>Why C is wrong:</strong> Self-employed people are not required by law to have private medical insurance.</li><li><strong>Why D is correct:</strong> All workers in the UK are legally entitled to 5.6 weeks (28 days for full-time) of paid holiday per year under the Working Time Regulations.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-7-employment-law:mcq:60d449b3', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which of the following is true about a contract of employment?", "options": ["An employer must give a worker a written contract of employment", "An employer must give a worker a written statement of particulars", "An employer does not have a contract with an employee until the worker has been given a written statement", "An employer can cancel a contract of employment without notice at any time"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Employers are legally required to provide a written statement of employment particulars on or before the first day of work. A contract of employment can be verbal — it exists as soon as the job offer is accepted, not when a written document is signed."}'::jsonb),
('business:3-7-employment-law:mcq:cad95422', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which of the following would break discrimination laws?", "options": ["An employer pays a female sales manager more than a male salesperson who has made fewer sales", "An employer promotes a white person who has more experience than a similarly qualified black person", "An employer does not send a gay man on a training course attended by all heterosexual workers doing the same job", "An employer spends money providing wheelchair access for workers"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Excluding a gay man from training available to all heterosexual colleagues doing the same job is direct sexual orientation discrimination. A is fine as it is merit-based. B is fine as experience is a legitimate reason. D is actually required by law for disability access."}'::jsonb),
('business:3-7-employment-law:mcq:38c40078', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "The working time directive states employers cannot normally ask workers to work more than an average of 48 hours per week in a 17-week period. In which case has the employer broken the law?", "options": ["An employer asks a worker to work 54 hours for 10 weeks then 36 hours for 7 weeks", "An employer asks a worker to work 714 hours in a 17-week period", "An employer asks a worker to work 850 hours in a 17-week period", "An employer asks a worker to work 60 hours for 9 weeks and 34 hours for 8 weeks"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. 850 &divide; 17 = 50 hours per week — this exceeds the 48-hour average. A = (54×10 + 36×7) &divide; 17 = 792 &divide; 17 = 46.6 hrs ✓. B = 714 &divide; 17 = 42 hrs ✓. D = (60×9 + 34×8) &divide; 17 = 812 &divide; 17 = 47.8 hrs ✓."}'::jsonb),
('business:3-7-employment-law:mcq:dc6a105d', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a benefit to a business of complying with employment laws?", "options": ["Workers may be better motivated", "Worker retention is likely to be better", "It will be easier to recruit new workers", "There may be costs to the business"]}'::jsonb, '{"answer": 3, "explain": "Correct: D. Costs are a drawback of complying with employment law, not a benefit. All the others (motivation, retention, easier recruitment) are genuine business benefits of treating staff fairly and legally."}'::jsonb),
('business:3-7-employment-law:mcq:c5b2a9f9', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "A contract of employment is:", "options": ["A diagram showing the formal lines of authority in a business", "A formal document outlining the objectives of a business", "A law that makes discrimination in the workplace illegal", "A legal agreement between an employer and an employee"]}'::jsonb, '{"answer": 3, "explain": "Correct: D. A contract of employment is a legal agreement between an employer and an employee formed when a job offer is accepted. It does not have to be in writing to exist. The Equality Act is the law against discrimination (C), and an organisational chart shows lines of authority (A)."}'::jsonb),
('business:3-7-employment-law:mcq:c56ac65c', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which one of the following is required by law?", "options": ["All employees must be given a voucher for a free eyesight test each year", "Employees who work from home must work a maximum of 16 hours a week", "Everyone who is self-employed must have private medical insurance", "Full-time employees must be given at least 5.6 weeks paid holiday per year"]}'::jsonb, '{"answer": 3, "explain": "Correct: D. All workers (not just full-time) are legally entitled to 5.6 weeks of paid holiday per year under UK law. Free eyesight tests apply only to screen-based workers (A), there is no 16-hour homeworking limit (B), and self-employed people are not required to have medical insurance (C)."}'::jsonb),
('business:3-7-employment-law:mcq:eb808018', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Emma worked 782 hours in a 17-week period. What is her average weekly hours?", "options": ["0.96 hours per week", "16.29 hours per week", "46 hours per week", "13,294 hours per week"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. 782 &divide; 17 = 46 hours per week. This is below the 48-hour legal limit, so no law has been broken. Option A divides 17 by 782 (wrong way round). Option B divides 782 by 48. Option D multiplies instead of divides."}'::jsonb),
('business:3-7-employment-law:mcq:b61ae5d6', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "The Equality Act 2010 protects workers from discrimination based on which of the following?", "options": ["Their salary level and number of years of experience", "Their race, gender, disability, sexual orientation, religion and age", "The number of hours they work per week", "Their qualifications and level of education"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. The Equality Act 2010 protects workers from discrimination on the grounds of race, gender, disability, sexual orientation, religion or belief, age, and marital status. Salary, experience, hours worked, and qualifications are not protected characteristics under the Act."}'::jsonb),
('business:3-7-employment-law:mcq:df6feb59', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which of the following correctly describes the Working Time Directive?", "options": ["It requires all workers to work exactly 40 hours per week", "It prevents employers asking workers to work more than 48 hours average per week over 17 weeks, though workers may opt out", "It applies equally to both employees and self-employed workers", "It sets a minimum of 30 days paid holiday for all workers"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. The Working Time Directive limits the average working week to 48 hours over 17 weeks, but workers can voluntarily opt out. It does NOT apply to self-employed people (C is wrong), does not set a fixed 40-hour week (A is wrong), and holiday entitlement is 5.6 weeks — not 30 days (D is wrong)."}'::jsonb),
('business:3-7-employment-law:mcq:e529f4c1', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "A business that is found guilty of sex discrimination by an employment tribunal could face which consequence?", "options": ["A warning letter from the government with no financial penalty", "Having to pay compensation to the affected employee and suffering reputational damage", "Being required to close its business for six months", "Losing its business licence permanently"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. An employment tribunal can award compensation to the affected worker and order the business to pay legal costs. This also causes significant reputational damage which can lead to a fall in sales and difficulty recruiting. Businesses are not closed or lose licences for discrimination."}'::jsonb),
('business:3-7-employment-law:mcq:eb82a0db', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "A worker who works 3 days per week is entitled to how many days of paid holiday per year?", "options": ["28 days", "16.8 days", "14 days", "5.6 days"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Holiday entitlement = days worked per week &times; 5.6. So 3 &times; 5.6 = 16.8 days. 28 days is for a full-time worker (5 days × 5.6). The formula always uses 5.6 — the number of weeks entitlement — multiplied by days worked."}'::jsonb),
('business:3-7-employment-law:mcq:318bf059', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of indirect discrimination?", "options": ["Refusing to hire a woman because she is female", "Paying a black employee less than a white employee doing the same job", "Locking a prayer room so Muslim workers must request a key and sign a book each time they pray", "Dismissing an employee for poor performance"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. The Tesco prayer room case is an example of indirect discrimination — a policy that appears neutral but disproportionately disadvantages members of a particular religion. A and B are examples of direct discrimination. D is lawful dismissal for performance reasons."}'::jsonb),
('business:3-7-employment-law:tf:fc382ce0', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "A contract of employment must be in writing to be legally valid."}'::jsonb, '{"answer": false, "explain": "FALSE. A contract of employment is formed the moment a job offer is accepted — verbally or in writing. The written document is the Statement of Employment Particulars, which is evidence of the contract, not the contract itself."}'::jsonb),
('business:3-7-employment-law:tf:28432a9c', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "All workers in the UK are legally entitled to 5.6 weeks of paid holiday per year."}'::jsonb, '{"answer": true, "explain": "TRUE. The law guarantees 5.6 weeks of paid holiday for all workers. For a full-time worker (5 days/week) this equals 28 days, including bank holidays."}'::jsonb),
('business:3-7-employment-law:tf:239cf1e2', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "The Working Time Directive applies to both employees and self-employed people."}'::jsonb, '{"answer": false, "explain": "FALSE. The Working Time Directive applies to employees only. Self-employed people are not covered, meaning an employer who hires a self-employed worker cannot be held responsible for the hours they work."}'::jsonb),
('business:3-7-employment-law:tf:dde792b3', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "A worker who clocks 914 hours over a 17-week period is working an average of over 48 hours per week."}'::jsonb, '{"answer": true, "explain": "TRUE. 914 &divide; 17 = 53.76 hours per week, which exceeds the 48-hour legal limit. The employer would be breaking the Working Time Directive unless the worker has voluntarily opted out."}'::jsonb),
('business:3-7-employment-law:tf:a52470fd', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "Employers are always allowed to refuse time off for religious observance."}'::jsonb, '{"answer": false, "explain": "FALSE. While there is no automatic right to time off for every religious festival, employers who refuse leave specifically because of an employee''s religion risk direct or indirect religious discrimination under the Equality Act 2010."}'::jsonb),
('business:3-7-employment-law:tf:e153a58a', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "A Statement of Employment Particulars must be provided to new employees on or before their first day of work."}'::jsonb, '{"answer": true, "explain": "TRUE. Since April 2020, employers must provide the written statement of employment particulars on or before the employee''s first day of work. This was changed from the previous two-month deadline."}'::jsonb),
('business:3-7-employment-law:tf:d2266ab8', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "A worker can be legally dismissed by their employer for refusing to work more than 48 hours per week."}'::jsonb, '{"answer": false, "explain": "FALSE. Employers cannot dismiss a worker for refusing to exceed the 48-hour average weekly limit. Workers have the legal right to stay within the limit. Dismissal for this reason would be unlawful."}'::jsonb),
('business:3-7-employment-law:tf:b920005c', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "The Equality Act 2010 protects workers from discrimination during recruitment and selection, not just once they are employed."}'::jsonb, '{"answer": true, "explain": "TRUE. The Equality Act 2010 covers the full employment relationship — including job advertisements, interviews, selection, pay, promotion, training, and dismissal. Employers can be taken to a tribunal for discriminatory recruitment practices."}'::jsonb),
('business:3-7-employment-law:tf:e4ced618', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "Under the Working Time Directive, workers under 18 can be asked to work up to 48 hours per week on average."}'::jsonb, '{"answer": false, "explain": "FALSE. Workers under 18 have a lower limit — they can only work a maximum of 40 hours per week (8 hours per day). They also cannot opt out of this limit."}'::jsonb),
('business:3-7-employment-law:tf:37eae1db', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "Businesses with strong anti-discrimination policies tend to find it easier to recruit new workers."}'::jsonb, '{"answer": true, "explain": "TRUE. Businesses with a good reputation for treating staff fairly attract a wider pool of applicants. Talented individuals are more likely to apply to businesses known for equal treatment, reducing the cost and difficulty of recruitment."}'::jsonb),
('business:3-7-employment-law:tf:0de4da26', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tf', 'tf', 1, '{"question": "A trade union can provide legal advice and pay for legal representation for members at an employment tribunal."}'::jsonb, '{"answer": true, "explain": "TRUE. Trade unions support members when employment rights may have been breached. They offer legal advice and may fund legal representation at tribunals — a significant benefit of union membership."}'::jsonb),
('business:3-7-employment-law:learn:60c8461a', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for the Employment Law topic.</p>\n<ul>\n  <li><strong>Employment Law:</strong> Regulations and rules put in place to protect workers from employers who may treat them unfairly.</li>\n  <li><strong>Contract of Employment:</strong> A legal agreement between an employer and an employee. It is formed when a job offer is accepted — it does not need to be in writing to exist.</li>\n  <li><strong>Statement of Employment Particulars:</strong> A written document that details the main terms of the contract of employment. It must be given to employees <em>on or before their first day of work</em>. It is NOT the contract itself — it is written evidence of it.</li>\n  <li><strong>Discrimination:</strong> Treating one worker differently from another for no acceptable reason.</li>\n  <li><strong>Equality Act 2010:</strong> An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace and beyond.</li>\n  <li><strong>Working Time Directive:</strong> A law stating the maximum number of hours that a person can be asked to work — normally an average of 48 hours per week over a 17-week period.</li>\n  <li><strong>Holiday Entitlement:</strong> The amount of paid holiday a worker is legally entitled to each year — 5.6 weeks (including bank holidays).</li>\n  <li><strong>Employment Tribunal:</strong> A panel that hears cases where employment laws may have been broken and comes to a decision in favour of the employer or employee.</li>\n  <li><strong>Trade Union:</strong> An employee organisation that exists to represent the interests of its members, including providing legal advice in tribunal cases.</li>\n  <li><strong>Opt Out:</strong> The right of a worker to voluntarily choose to work more than 48 hours per week.</li>\n</ul>", "question": "What is the difference between a contract of employment and a Statement of Employment Particulars?", "options": ["The statement is evidence of the contract, not the contract itself", "They are exactly the same legal document", "The contract must always be signed, but the statement is optional", "The statement is only needed for self-employed workers"]}'::jsonb, '{"answer": 0, "explain": "The contract of employment exists the moment a job offer is accepted — it doesn''t need to be in writing. The statement of particulars is a separate written document that provides evidence of the contract''s terms."}'::jsonb),
('business:3-7-employment-law:learn:1db40eee', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "The Equality Act 2010 — Types of Discrimination", "reading": "<p>The <strong>Equality Act 2010</strong> brought together 116 pieces of legislation into one single Act. It protects workers from discrimination in recruitment, pay, promotion, training, terms of employment, and dismissal.</p>\n<p>A business <strong>must not</strong>:</p>\n<ul>\n  <li>Pay workers differently for doing the same work</li>\n  <li>Favour certain types of people when recruiting</li>\n  <li>Discriminate when promoting or training workers</li>\n  <li>Allow workers to be mistreated by other workers</li>\n</ul>\n<p>The six main types of discrimination under the Act are:</p>\n<ul>\n  <li><strong>Equal Pay Discrimination:</strong> Women must be paid the same as men when doing work of equal value. <em>Example: Samira Ahmed v BBC — she was awarded £700,000 after her role was found to be comparable to a male presenter paid far more.</em></li>\n  <li><strong>Racial Discrimination:</strong> People cannot be treated differently because of their race, colour, nationality or ethnic origin.</li>\n  <li><strong>Sex Discrimination:</strong> Men or women cannot be treated differently due to gender. Job ads cannot specify gender unless there is a genuine reason (e.g. a female PE teacher for a girls'' changing room).</li>\n  <li><strong>Disability Discrimination:</strong> Employers cannot discriminate against disabled people when recruiting. They must make reasonable adjustments to premises and provide appropriate equipment.</li>\n  <li><strong>Sexual Orientation Discrimination:</strong> Applies to lesbian, gay, bisexual, heterosexual, and gender-reassigned people. No preference of any kind may be given based on sexual orientation.</li>\n  <li><strong>Religion or Belief Discrimination:</strong> Workers are protected from discrimination based on religious beliefs or lack of them. Employers should allow time off for important religious festivals.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Tesco & Muslim Prayer Room</h4>\n  <p>Two Muslim workers took Tesco to a tribunal after their prayer room was locked and they were made to sign a book and request a key each time they prayed. Tesco were found guilty of <strong>indirect religious discrimination</strong> — the rules placed Muslims at an unfair disadvantage compared to other workers.</p>\n</div>", "question": "Why was Tesco found guilty of discrimination in the prayer room case study?", "options": ["They directly refused to let Muslim workers pray at all", "Indirect discrimination disadvantaged Muslim staff unfairly", "They paid Muslim workers less than other staff", "They did not hire any Muslim applicants"]}'::jsonb, '{"answer": 1, "explain": "This is a case of indirect discrimination: a policy that looks neutral on the surface but disproportionately disadvantages a particular group — in this case, Muslim workers needing regular access to pray."}'::jsonb),
('business:3-7-employment-law:learn:d2228929', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Working Time Directive — Hours of Work", "reading": "<p>The <strong>Working Time Directive</strong> limits the number of hours an employer can ask an adult worker to work. The limit is an average of <strong>48 hours per week over a 17-week period</strong>.</p>\n<div class=\"formula-box\">\n  <strong>Average Hours per Week =</strong> Total hours worked &divide; 17\n</div>\n<p><strong>Example:</strong> A worker worked 799 hours in 17 weeks → 799 &divide; 17 = <strong>47 hours per week</strong> (within the limit).</p>\n<p><strong>Example:</strong> A worker worked 914 hours in 17 weeks → 914 &divide; 17 = <strong>53.76 hours per week</strong> (above the limit — law broken).</p>\n<p>Key exceptions and rules to know:</p>\n<ul>\n  <li>Workers can <strong>opt out</strong> voluntarily — they can agree to work more than 48 hours</li>\n  <li>The law applies to <strong>employees</strong> only — it does <strong>not</strong> apply to self-employed people</li>\n  <li>Workers under 18 can only work up to <strong>40 hours</strong> per week</li>\n  <li>Workers must receive a <strong>20-minute rest break</strong> every 6 hours</li>\n  <li>Exceptions: armed forces, police, emergency services, managing directors, seamen</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Uber Drivers (2021 Supreme Court)</h4>\n  <p>Uber claimed its drivers were self-employed independent contractors and therefore not entitled to holidays, pensions, or minimum wage. The Supreme Court ruled that because Uber controlled drivers'' pay, routes, and penalised those who declined jobs, the drivers were in fact <strong>workers</strong>. Uber subsequently granted them employee status and benefits.</p>\n</div>", "question": "A worker clocks 884 hours over a 17-week period. Has the Working Time Directive been broken?", "options": ["Yes — 884 ÷ 17 = 52 hours per week, above the 48-hour limit", "No — 884 ÷ 17 = 48 hours per week exactly", "No — the law doesn''t apply unless they work over 60 hours", "It cannot be worked out from this information"]}'::jsonb, '{"answer": 0, "explain": "884 ÷ 17 = 52 hours per week, which is above the 48-hour average limit — so the law has been broken unless the worker has voluntarily opted out."}'::jsonb),
('business:3-7-employment-law:learn:9cd96c97', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Holiday Entitlement", "reading": "<p>By law, all workers in the UK are entitled to <strong>5.6 weeks of paid holiday per year</strong>. This includes bank holidays (8 per year in the UK). Workers must be paid their <em>normal earnings</em> while on holiday — not just basic pay.</p>\n<div class=\"formula-box\">\n  <strong>Holiday Entitlement (days) =</strong> Days worked per week &times; 5.6\n</div>\n<p><strong>Examples:</strong></p>\n<ul>\n  <li>Full-time (5 days/week): 5 &times; 5.6 = <strong>28 days</strong></li>\n  <li>Part-time (2 days/week): 2 &times; 5.6 = <strong>11.2 days</strong></li>\n</ul>\n<p>Employers cannot reduce holiday entitlement without employee consent. Businesses must plan staffing carefully to ensure enough workers are available when others are on holiday — this may mean <strong>hiring additional staff</strong>.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Mr Lock v British Gas</h4>\n  <p>Mr Lock was a salesman paid a basic salary plus commission. When on holiday, he only received basic pay — significantly less than normal. A tribunal ruled he must be paid a sum equal to his <strong>average monthly earnings</strong>, including typical commission. This set an important precedent for workers whose normal pay includes variable elements.</p>\n</div>", "question": "A worker is employed 4 days per week. How many days of paid holiday are they entitled to per year?", "options": ["28 days", "22.4 days", "5.6 days", "4 days"]}'::jsonb, '{"answer": 1, "explain": "Holiday entitlement = days worked per week × 5.6. So 4 × 5.6 = 22.4 days. 28 days only applies to full-time workers (5 days × 5.6)."}'::jsonb),
('business:3-7-employment-law:learn:9e9e22d3', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Contract of Employment — Statement of Particulars", "reading": "<p>A <strong>contract of employment</strong> exists as soon as a job offer is accepted — it does not need to be in writing. However, employers must provide a <strong>Statement of Employment Particulars</strong> on or before the first day of work.</p>\n<p>The statement must include:</p>\n<ul>\n  <li>Names and addresses of employer and employee</li>\n  <li>Start date of employment</li>\n  <li>Job title and description</li>\n  <li>Hours of work</li>\n  <li>Rate and frequency of pay</li>\n  <li>Holiday entitlement</li>\n  <li>Sick pay arrangements</li>\n  <li>Pension rights</li>\n  <li>Notice period required from both sides</li>\n  <li>Probationary period (if applicable)</li>\n</ul>\n<p>The statement helps to <strong>avoid disputes</strong> about pay, hours, and holidays. Once agreed, it restricts what the employer can ask the employee to do — affecting the <strong>human resource needs</strong> of the business.</p>\n<p>⚠️ <strong>Common misconception:</strong> Many students confuse the contract with the statement. The contract is the <em>legal agreement</em>; the statement is the <em>written evidence</em> of that agreement.</p>", "question": "Which of these must be included in a Statement of Employment Particulars?", "options": ["The employee''s school exam results", "Start date, job title, hours, and pay", "The employer''s annual company profits", "A list of all other employees'' salaries"]}'::jsonb, '{"answer": 1, "explain": "The statement must include key terms such as start date, job title, hours, pay, holiday entitlement, sick pay, pension rights, and notice periods — not personal or unrelated company information."}'::jsonb),
('business:3-7-employment-law:learn:84b9f854', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Impact of Employment Law on Businesses", "reading": "<p>Businesses are affected by employment law in both positive and negative ways. It is important to evaluate both sides for exam questions.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Complying</div>\n    <div class=\"pro-item\"><strong>Motivated workforce:</strong> Workers see the business as a good employer and are more productive, improving efficiency.</div>\n    <div class=\"pro-item\"><strong>Better staff retention:</strong> Workers treated fairly are less likely to leave, reducing recruitment and training costs.</div>\n    <div class=\"pro-item\"><strong>Easier recruitment:</strong> A business with a good reputation for fair treatment attracts a wider pool of applicants.</div>\n    <div class=\"pro-item\"><strong>Avoids legal penalties:</strong> Complying means the business avoids costly fines, compensation payments, and tribunal proceedings.</div>\n    <div class=\"pro-item\"><strong>Strong brand reputation:</strong> Ethical employment practices can positively affect customer perception and sales revenue.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Costs of Complying</div>\n    <div class=\"con-item\"><strong>Higher wage costs:</strong> Limits on hours mean hiring more staff to cover the same workload; minimum wage rises increase the wage bill.</div>\n    <div class=\"con-item\"><strong>Administration costs:</strong> Businesses must write recruitment policies, produce contracts, and monitor compliance — this requires time and possibly specialist staff.</div>\n    <div class=\"con-item\"><strong>Court costs:</strong> If taken to a tribunal, the business must pay for legal representation even if found not guilty.</div>\n    <div class=\"con-item\"><strong>Fines and compensation:</strong> If found guilty of breaking employment law, a business must pay fines or large compensation awards (e.g. Sberbank paid over £3 million).</div>\n    <div class=\"con-item\"><strong>Reputational damage:</strong> Bad publicity from tribunal cases can lead to a fall in sales and difficulty recruiting future staff.</div>\n  </div>\n</div>", "question": "Which of the following is a genuine BUSINESS benefit of complying with employment law (not just an employee benefit)?", "options": ["Employees feel happier at work", "Easier recruitment due to reputation", "Workers get more holiday days", "Staff are treated with more respect"]}'::jsonb, '{"answer": 1, "explain": "Examiners want business-level outcomes — easier recruitment, lower staff turnover, avoiding fines, and stronger reputation — not statements about how employees feel, which are not direct business benefits."}'::jsonb),
('business:3-7-employment-law:learn:b44d6f98', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'learn', 'mcq', 1, '{"readingTitle": "Employment Tribunals & Trade Unions", "reading": "<p>If a worker feels their employment rights have been breached, they can take their employer to an <strong>employment tribunal</strong>.</p>\n<ul>\n  <li>A tribunal is a panel including a <strong>legally qualified chairperson</strong> and other experts</li>\n  <li>It hears evidence from both the employee and employer</li>\n  <li>It can <strong>impose fines, award compensation</strong>, and order costs to be paid</li>\n  <li>Workers are often supported by a <strong>trade union</strong>, which provides legal advice and may fund legal representation</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Sberbank Sex Discrimination</h4>\n  <p>Svetlana Lokhova, a highly regarded investment banker, was awarded over £3 million after an employment tribunal found she had been subjected to <strong>sex discrimination</strong> at Sberbank''s London office. Her direct manager sent derogatory emails about her to colleagues and clients. The case damaged Sberbank''s reputation, cost significant legal fees, and led to reduced staff morale and recruitment challenges.</p>\n</div>", "question": "What support can a trade union provide to a worker who believes their employment rights have been breached?", "options": ["Legal advice and possible tribunal funding", "A guaranteed pay rise", "Automatic promotion to a management role", "Permission to break workplace rules"]}'::jsonb, '{"answer": 0, "explain": "Trade unions represent the interests of their members by offering legal advice and, in many cases, funding legal representation at an employment tribunal."}'::jsonb),
('business:3-7-employment-law:misc:b67eda0f', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A contract of employment must be in writing to exist.</p><p><strong>✅ The correct idea:</strong> A contract of employment is formed the moment a job offer is accepted — verbally is enough. The written document is the Statement of Employment Particulars, which is evidence of the contract, not the contract itself.</p>", "question": "When does a contract of employment legally come into existence?", "options": ["Only after the first day of work", "Only once the Statement of Particulars is issued", "Only once it is signed in writing", "The moment a job offer is accepted"]}'::jsonb, '{"answer": 3, "explain": "A contract is formed as soon as a job offer is accepted, even verbally — it does not need to be written down to be legally binding."}'::jsonb),
('business:3-7-employment-law:misc:0f341a37', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Statement of Employment Particulars IS the contract of employment.</p><p><strong>✅ The correct idea:</strong> They are different things. The contract is the legal agreement (formed verbally or in writing). The statement is a written document that records the main terms of that contract. Students often mix these up in exams.</p>", "question": "What is the relationship between the contract of employment and the Statement of Particulars?", "options": ["The statement replaces the need for a contract", "The contract is only valid after the statement is signed", "The statement is evidence of the contract, not the contract", "They are the same document"]}'::jsonb, '{"answer": 2, "explain": "The contract is the legal agreement itself. The statement is a separate written document that records its main terms — evidence of the contract, not the contract."}'::jsonb),
('business:3-7-employment-law:misc:5ef3b2eb', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Working Time Directive applies to everyone, including self-employed workers.</p><p><strong>✅ The correct idea:</strong> The directive only applies to employees. Self-employed people are not covered, so employers cannot be held responsible for the hours a self-employed contractor works.</p>", "question": "Does the Working Time Directive apply to self-employed workers?", "options": ["Only if they work more than 48 hours", "Only in certain industries", "Yes, equally to everyone", "No — it only applies to employees"]}'::jsonb, '{"answer": 3, "explain": "The Working Time Directive applies to employees only. Self-employed people are not covered by the 48-hour average limit."}'::jsonb),
('business:3-7-employment-law:misc:83de50d2', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Employers can always refuse time off for prayer or religious festivals.</p><p><strong>✅ The correct idea:</strong> Refusing leave specifically because of an employee''s religion risks a discrimination claim. Employers do not have to grant every request, but a blanket refusal based on religion is likely to be indirect discrimination.</p>", "question": "What risk does an employer take if they always refuse time off requested for religious reasons?", "options": ["A possible indirect discrimination claim", "No risk — employers can always refuse", "Nothing, as long as it applies to all staff equally", "A fine from the Working Time Directive"]}'::jsonb, '{"answer": 0, "explain": "A blanket refusal of time off specifically because of religion can amount to indirect discrimination, even if the policy appears neutral on the surface."}'::jsonb),
('business:3-7-employment-law:misc:2b40d1c6', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing ''fair pay'' or ''treating employees fairly'' is a valid answer when asked for an aspect of employment law.</p><p><strong>✅ The correct idea:</strong> Examiners will not award marks for these vague ethical statements. You must name a specific legal aspect, such as ''minimum wage'', ''discrimination law'', ''working hours'', or ''holiday entitlement''.</p>", "question": "Why would an exam answer of ''treating employees fairly'' score zero marks?", "options": ["It is too long an answer", "It''s spelled incorrectly", "It only applies to full-time workers", "Too vague and ethical, not a named law"]}'::jsonb, '{"answer": 3, "explain": "Examiners need a specific, named legal aspect (e.g. discrimination, working hours, minimum wage) — vague ethical statements about fairness do not name an actual law."}'::jsonb),
('business:3-7-employment-law:misc:a3e4cc17', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Giving two types of discrimination (e.g. racism and ageism) counts as two separate aspects of employment law.</p><p><strong>✅ The correct idea:</strong> Examiners treat these as repetitions of the same point — both are discrimination. To get two marks, give two different aspects, such as ''discrimination'' AND ''working hours''.</p>", "question": "If a student writes ''racism'' and ''ageism'' as their two aspects of employment law, how many marks do they get?", "options": ["1 mark — both are discrimination, a repeated point", "2 marks — they are different forms of discrimination", "0 marks — neither is a valid aspect", "3 marks — bonus for detail"]}'::jsonb, '{"answer": 0, "explain": "Racism and ageism are both types of discrimination, so writing both only counts as one valid point. To score 2 marks, you need two genuinely different aspects, e.g. discrimination AND working hours."}'::jsonb),
('business:3-7-employment-law:misc:253eb376', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Workers who opt out of the 48-hour limit can be forced to work unlimited hours by their employer.</p><p><strong>✅ The correct idea:</strong> Opting out must be completely voluntary. Employers cannot force workers to opt out, and cannot dismiss or punish a worker who refuses to opt out.</p>", "question": "Can an employer force a worker to opt out of the 48-hour limit?", "options": ["Yes, if the worker is paid extra", "No — opting out must be voluntary", "Yes, if business needs require it", "Yes, but only for new employees"]}'::jsonb, '{"answer": 1, "explain": "Opting out of the 48-hour limit must be a free, voluntary choice by the worker. Employers cannot force it, and cannot punish a worker for refusing to opt out."}'::jsonb),
('business:3-7-employment-law:misc:bec136ad', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Employment law only affects large businesses with many employees.</p><p><strong>✅ The correct idea:</strong> Employment law applies to ALL businesses regardless of size. Even a sole trader taking on one employee must comply with rules on contracts, minimum wage, working hours, and anti-discrimination law.</p>", "question": "Does employment law apply to a sole trader who hires just one employee?", "options": ["Only if the business has over 10 employees", "No — only large businesses are affected", "Only if the employee works full-time", "Yes — employment law applies to every business"]}'::jsonb, '{"answer": 3, "explain": "Employment law applies to every business, no matter how small — even a sole trader hiring a single employee must comply with contract, minimum wage, working hours, and discrimination rules."}'::jsonb),
('business:3-7-employment-law:misc:02c922b4', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked for an advantage to the BUSINESS of having an anti-discrimination policy, students write ''employees feel safer or happier''.</p><p><strong>✅ The correct idea:</strong> Examiners reject answers about employee feelings as they are not directly an advantage to the business. Instead, write about business-level outcomes: easier recruitment, lower staff turnover, stronger reputation, or higher productivity.</p>", "question": "Why does ''employees feel happier'' NOT count as a business advantage in an exam answer?", "options": ["It''s not specific enough about feelings", "It is only true for large businesses", "An employee outcome, not a business outcome", "Happiness cannot be measured"]}'::jsonb, '{"answer": 2, "explain": "Exam answers need business-level outcomes — easier recruitment, lower staff turnover, stronger reputation, higher productivity — not statements about how employees feel, which examiners do not credit as a direct business benefit."}'::jsonb),
('business:3-7-employment-law:tips:11a16de9', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify — 1–2 marks — Be Specific — Name the Law, Not the Feeling", "reading": "\n      <p>A ''State'' or ''Identify'' question needs one clear, specific point per mark. Do not write vague or ethical answers — examiners will award <strong>zero marks</strong> for these.</p>\n\n      <p><strong>❌ Bad Answers (0 marks):</strong></p>\n      <ul>\n        <li>\"Fair pay\" — this is an ethical point, not a legal one</li>\n        <li>\"Treated fairly\" — too vague, not a legal requirement</li>\n        <li>\"Employment rights\" — too broad, no specific law named</li>\n        <li>\"Pay\" or \"how much they are paid\" — too vague</li>\n      </ul>\n\n      <p><strong>✅ Good Answers (1 mark each):</strong></p>\n      <ul>\n        <li>\"Discrimination / equal pay / disability rights\"</li>\n        <li>\"Working hours / limit on hours worked\"</li>\n        <li>\"Minimum/living wage\"</li>\n        <li>\"Holiday entitlement\"</li>\n        <li>\"Contract of employment / statement of particulars\"</li>\n        <li>\"Maternity/paternity pay\"</li>\n      </ul>\n\n      <p>⚠️ <strong>Examiner Warning:</strong> If a question asks for <em>two</em> aspects and you write ''racism'' and ''ageism'', you will only get <strong>1 mark</strong> — both are types of discrimination and count as the same point.</p>\n    ", "question": "Which of these would score a mark in a ''State an aspect of employment law'' question?", "options": ["\"Employment rights\"", "\"Discrimination\"", "\"Fair pay\"", "\"Treated fairly\""]}'::jsonb, '{"answer": 1, "explain": "Only specific, named legal aspects like discrimination, minimum wage, or holiday entitlement score marks. Vague ethical phrases like ''fair pay'' or ''treated fairly'' score zero."}'::jsonb),
('business:3-7-employment-law:tips:ad471af2', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Knowledge + Application = Full Marks", "reading": "\n      <p>A 2-mark ''Explain'' question needs two things: a point of <strong>knowledge</strong> about employment law AND an <strong>application</strong> to the specific business in the case study.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>K (1 mark):</strong> State the employment law / aspect</li>\n        <li><strong>APP (1 mark):</strong> Link it directly to the named business</li>\n      </ul>\n\n      <p>⚠️ <strong>Critical Rule:</strong> You cannot earn the application mark without the knowledge mark first. Always make your point of knowledge before applying it.</p>\n\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"Employment law means Greggs cannot discriminate.\"</em><br/>\n      — No application to the business context.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Employment law ensures that all 20,000 Greggs employees (APP) are not discriminated against on grounds such as disability or ethnicity (K).\"</em></p>\n\n      <p><strong>Sentence Starter:</strong><br/>\n      \"Employment law means that [business name] must… [specific legal requirement], which affects the business because…\"</p>\n    ", "question": "What is missing from this 2-mark answer: \"Employment law means Greggs cannot discriminate\"?", "options": ["A case study reference", "An application linked to Greggs", "Nothing — it scores full marks", "A formula"]}'::jsonb, '{"answer": 1, "explain": "This answer only gives the knowledge point (K). To earn both marks it needs an application — a specific link to the named business, such as Greggs'' 20,000 employees."}'::jsonb),
('business:3-7-employment-law:tips:b0d5407f', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark ''Analyse'' question requires three separate steps. Missing any one step means missing a mark. The most common mistake is failing to reach the <strong>impact</strong> stage.</p>\n\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>U (1 mark):</strong> State and explain the employment law point</li>\n        <li><strong>APP (1 mark):</strong> Apply it directly to the specific business using details from the case study</li>\n        <li><strong>AN (1 mark):</strong> State the financial or operational impact on the business — costs, revenue, reputation, etc.</li>\n      </ul>\n\n      <p>🚫 <strong>Knowledge Dumping Alert:</strong> Do NOT just write everything you know about employment law. Examiners reward analysis — following the chain of impact — not volume of facts.</p>\n\n      <p><strong>The \"So What?\" Rule:</strong> After every sentence, ask yourself \"So what does this mean for the business?\" Keep pushing until you reach a bottom-line impact.</p>\n\n      <p><strong>❌ Bad Answer:</strong><br/>\n      <em>\"Saranne must not discriminate against workers. This is because the Equality Act says so.\"</em><br/>\n      — Knowledge only. No application. No analysis. = 1 mark.</p>\n\n      <p><strong>✅ Model Answer (3 marks):</strong><br/>\n      <em>\"Employers must ensure equality of opportunity during recruitment (U). Saranne, who is opening a new bookshop and hiring three employees for the first time (APP), must make sure her job advertisement does not specify preferences based on age or gender. If she breaks this law, she could face a tribunal and be forced to pay compensation, which would significantly increase her start-up costs and damage her reputation before the business has even opened (AN).\"</em></p>\n\n      <p><strong>Sentence Starters:</strong><br/>\n      U: \"Employment law requires that…\"<br/>\n      APP: \"In the case of [business name], who [context from case study]…\"<br/>\n      AN: \"This means that… leading to a rise in costs / fall in profit / damage to reputation…\"</p>\n    ", "question": "What are the three steps required for full marks on a 3-mark Analyse question?", "options": ["Knowledge, Application, Analysis", "Two examples and an evaluation", "Definition, Example, Conclusion", "Knowledge repeated three times"]}'::jsonb, '{"answer": 0, "explain": "The three-step formula is U (state the law) → APP (apply it to the named business) → AN (explain the financial or operational impact). Missing the final impact step is the most common way to lose a mark."}'::jsonb),
('business:3-7-employment-law:tips:8e2e4ae8', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Impacts — 6 marks — Two Full Chains — No Conclusion Needed", "reading": "\n      <p>A 6-mark question is simply two 3-mark analyses written back-to-back. You need <strong>two separate employment law impacts</strong>, each fully developed with U → APP → AN.</p>\n\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> U + APP + AN (3 marks)</li>\n        <li><strong>Point 2:</strong> U + APP + AN (3 marks)</li>\n      </ul>\n\n      <p>⚠️ <strong>Warning:</strong> There are <strong>zero marks</strong> available for a conclusion or evaluation in a 6-mark question. Do not write one — it wastes time.</p>\n\n      <p>⚠️ <strong>Warning:</strong> Do not make two points about the same aspect of employment law (e.g. two points about discrimination). Choose two different laws or impacts.</p>\n\n      <p><strong>Good pairings of points to use:</strong></p>\n      <ul>\n        <li>Discrimination law + Working time directive</li>\n        <li>Minimum wage / wage costs + Reputation / recruitment impact</li>\n        <li>Anti-discrimination costs + Tribunal / compensation costs</li>\n      </ul>\n\n      <p><strong>Sentence Starters (Point 1):</strong><br/>\n      \"One way employment law impacts [business] is… This means… As a result, the business will…\"</p>\n\n      <p><strong>Sentence Starters (Point 2):</strong><br/>\n      \"A second way employment law affects [business] is… Because [case study detail]… This could lead to…\"</p>\n    ", "question": "Should you write a conclusion or evaluation at the end of a 6-mark Analyse question?", "options": ["No — no marks for a conclusion", "Only if you have time left", "Yes, but only one sentence", "Yes — it''s worth an extra mark"]}'::jsonb, '{"answer": 0, "explain": "A 6-mark question is two separate 3-mark analysis chains. There are no marks for a conclusion or evaluation here — writing one only wastes exam time."}'::jsonb),
('business:3-7-employment-law:tips:745d0c14', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'tips', 'mcq', 1, '{"readingTitle": "Calculation — Working Time & Holiday — Master the Formulas Before the Exam", "reading": "\n      <p>There are two calculations you must know for this topic. Practise them until they are automatic.</p>\n\n      <p><strong>Formula 1 — Average Weekly Hours:</strong></p>\n      <ul>\n        <li>Total hours worked &divide; 17 = Average hours per week</li>\n        <li>If the result is <strong>above 48</strong> → law is broken (unless the worker opted out)</li>\n        <li>If the worker is <strong>self-employed</strong> → the law does not apply regardless</li>\n      </ul>\n\n      <p><strong>Formula 2 — Holiday Entitlement:</strong></p>\n      <ul>\n        <li>Days worked per week &times; 5.6 = Days holiday per year</li>\n        <li>Full-time (5 days): 5 × 5.6 = <strong>28 days</strong></li>\n        <li>Part-time (3 days): 3 × 5.6 = <strong>16.8 days</strong></li>\n      </ul>\n\n      <p>⚠️ <strong>Common mistakes:</strong></p>\n      <ul>\n        <li>Dividing 17 by the hours (wrong way round)</li>\n        <li>Forgetting to check if the worker is self-employed</li>\n        <li>Thinking 48 hours is a hard weekly cap rather than a 17-week average</li>\n      </ul>\n    ", "question": "A part-time worker works 2 days per week. Using the holiday entitlement formula, how many days holiday are they entitled to?", "options": ["2 days", "5.6 days", "11.2 days", "28 days"]}'::jsonb, '{"answer": 2, "explain": "Holiday entitlement = days worked per week × 5.6. So 2 × 5.6 = 11.2 days."}'::jsonb),
